// Deduplicate and prepare articles for AI processing
const seen = new Set();
const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - 7); // only last 7 days

const cleaned = [];

for (const item of $input.all()) {
  const url = item.json.link || item.json.url || '';
  const title = item.json.title || '';

  // Skip if already seen (dedup by URL)
  if (seen.has(url) || !url || !title) continue;
  seen.add(url);

  // Skip if older than 7 days
  const pubDate = item.json.pubDate || item.json.isoDate || item.json.date;
  if (pubDate) {
    const articleDate = new Date(pubDate);
    if (articleDate < cutoffDate) continue;
  }

  // Skip very short titles (usually junk)
  if (title.length < 15) continue;

  cleaned.push({
    json: {
      title: title.substring(0, 200),
      url: url,
      description: (item.json.contentSnippet || item.json.summary || item.json.content || '').substring(0, 500),
      date: pubDate || new Date().toISOString(),
      sourceName: item.json.meta?.title || item.json.source || 'Unknown'
    }
  });
}

// Limit to 50 most recent to stay within Gemini token limits
return cleaned.slice(0, 50);

// Parse Gemini response and extract the JSON article object
const results = [];

for (const item of $input.all()) {
  try {
    // Get the text from Gemini's response
    const text = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';

    // Clean up any accidental markdown
    const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();

    // Parse the JSON
    const article = JSON.parse(cleaned);

    // Validate required fields
    if (article.title && article.url && article.category) {
      results.push({ json: article });
    }
  } catch (e) {
    // Skip malformed responses silently
    console.log('Skipping malformed Gemini response:', e.message);
  }
}

return results;

// Aggregate all processed articles into a single feed.json structure
const articles = $input.all().map(item => item.json);

// Remove duplicates by URL (belt and suspenders)
const seen = new Set();
const unique = articles.filter(a => {
  if (seen.has(a.url) || !a.url) return false;
  seen.add(a.url);
  return true;
});

// Sort newest first
unique.sort((a, b) => new Date(b.date) - new Date(a.date));

const feedData = {
  lastUpdated: new Date().toISOString(),
  source: 'GOAT Publications AI Feed Agent — Powered by Gemini',
  totalItems: unique.length,
  items: unique
};

return [{ json: feedData }];

// Convert the feed data to a base64-encoded string for GitHub API
const feedData = $input.first().json;
const jsonString = JSON.stringify(feedData, null, 2);
const base64Content = Buffer.from(jsonString).toString('base64');

return [{
  json: {
    feedData: feedData,
    base64Content: base64Content,
    message: `Auto-update: ChE Feed — ${feedData.totalItems} articles — ${new Date().toUTCString()}`
  }
}];

const result = $input.first().json;
const commit = result.commit?.sha?.substring(0, 7) || 'unknown';
const articles = $('Build feed.json').first().json.totalItems;

console.log(`✅ GOAT Feed updated successfully!`);
console.log(`📰 Articles: ${articles}`);
console.log(`🔗 Commit: ${commit}`);
console.log(`⏰ Time: ${new Date().toUTCString()}`);
console.log(`🚀 Netlify will auto-deploy in ~30 seconds`);

return [{ json: { success: true, articles, commit, timestamp: new Date().toISOString() } }];
